const config = $('HTTP Request Config').first().json;
const webhook = $('Recibir Mensaje').first().json.body;

const jidOriginal = webhook.jidOriginal || webhook.numeroOrigen;
const numeroDescifrado = webhook.numeroDescifrado || false;

const ZONA_HORARIA = 'America/Hermosillo';
const now = new Date();
const horaLocal = new Date(now.toLocaleString('en-US', { timeZone: ZONA_HORARIA }));
const hour = horaLocal.getHours();
const day = horaLocal.getDay();

const horaInicio = config.horario_inicio
  ? parseInt(config.horario_inicio.split(':')[0])
  : (config.hora_inicio || 9);
const horaFin = config.horario_fin
  ? parseInt(config.horario_fin.split(':')[0])
  : (config.hora_fin || 18);

let diasLaborales = [1, 2, 3, 4, 5];
if (config.dias_laborales) {
  try {
    diasLaborales = typeof config.dias_laborales === 'string'
      ? JSON.parse(config.dias_laborales)
      : config.dias_laborales;
  } catch (e) {}
}

const enDiaLaboral = diasLaborales.includes(day);
const enHorario = hour >= horaInicio && hour < horaFin;
const abierto = enDiaLaboral && enHorario;

const mensaje = webhook.mensaje || '';
const mensajeLimpio = mensaje.toLowerCase().trim();

let nombreSesion = config.sessionKey ||
                   webhook.sessionKey ||
                   `${webhook.empresaId}_empresa_${webhook.empresaId}`;
if (nombreSesion && nombreSesion.startsWith(`${webhook.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${webhook.empresaId}_`.length);
}

console.log('═══════════════════════════════════════════════════');
console.log('📅 [RESERVACIONES] MENSAJE:', mensajeLimpio);
console.log('📞 Usuario:', webhook.numeroOrigen);
console.log('═══════════════════════════════════════════════════');

// ═══════════════════════════════════════════════════════
// PRIORIDAD 1: CANCELAR CITA ESPECÍFICA
// ═══════════════════════════════════════════════════════
const patronCancelarEspecifico = /\b(?:cancelar|cancela)\s+(?:cita|reserva|reservacion|turno)\s*#?(\d+)\b/i;
const matchCancelar = mensajeLimpio.match(patronCancelarEspecifico);

if (matchCancelar) {
  const citaId = matchCancelar[1];
  console.log(`🎯 DETECTADO: Cancelar cita #${citaId}`);
  return {
    json: {
      ...config,
      numeroOrigen: webhook.numeroOrigen,
      empresaId: webhook.empresaId,
      nombreSesion,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      mensaje_usuario: mensajeLimpio,
      citaId: parseInt(citaId),
      tipo: 'cancelar_cita',
      mensaje: `🔄 *Procesando cancelación de la cita #${citaId}...*`,
      abierto
    }
  };
}

// ═══════════════════════════════════════════════════════
// PRIORIDAD 2: VER MIS CITAS
// ═══════════════════════════════════════════════════════
const patronCancelarGeneral = /^(?:cancelar|cancela)$/i;
const esCancelarGeneral = patronCancelarGeneral.test(mensajeLimpio);

if (!esCancelarGeneral) {
  const patronVerCitas = /\b(mis?\s+citas?|ver\s+mis?\s+citas?|mis?\s+reservas?|mis?\s+reservaciones?|ver\s+mis?\s+reservas?|consultar\s+citas?|mis?\s+turnos?|historial|ver\s+citas?)\b/i;
  if (patronVerCitas.test(mensajeLimpio)) {
    console.log('✅ DETECTADO: Ver citas');
    return {
      json: {
        ...config,
        numeroOrigen: webhook.numeroOrigen,
        empresaId: webhook.empresaId,
        nombreSesion,
        pushName: webhook.pushName,
        jidOriginal,
        numeroDescifrado,
        mensaje_usuario: mensajeLimpio,
        tipo: 'ver_citas',
        mensaje: '📋 *Consultando tus citas...*',
        abierto
      }
    };
  }
}

// ═══════════════════════════════════════════════════════
// PRIORIDAD 3: VERIFICAR SESIÓN ACTIVA DE RESERVACIÓN
// ═══════════════════════════════════════════════════════
try {
  const sesionData = await this.helpers.httpRequest({
    method: 'GET',
    url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
    json: true
  });

  if (sesionData && sesionData.success && sesionData.data) {
    const estadoActual = sesionData.data.estado;
    console.log('📋 Sesión reservación encontrada - Estado:', estadoActual);

    const datosSesion = typeof sesionData.data.datos_pedido === 'string'
      ? JSON.parse(sesionData.data.datos_pedido)
      : sesionData.data.datos_pedido;

    // ── SELECCIONANDO SERVICIO ─────────────────────────────────────────
    if (estadoActual === 'seleccionando_servicio') {
      const servicios = datosSesion?.servicios || [];

      if (mensajeLimpio === 'cancelar') {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '✅ Operación cancelada.\n\n📋 Escribe *servicios* para ver nuestro catálogo.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }

      const opcion = parseInt(mensajeLimpio);
      if (!isNaN(opcion) && opcion >= 1 && opcion <= servicios.length) {
        const servicioElegido = servicios[opcion - 1];
        // Actualizar sesión con servicio seleccionado
        await this.helpers.httpRequest({
          method: 'PUT',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          headers: { 'Content-Type': 'application/json' },
          body: {
            estado: 'seleccionando_fecha',
            datosPedido: { ...datosSesion, servicioSeleccionado: servicioElegido }
          },
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            tipo: 'pedir_fecha',
            servicioSeleccionado: servicioElegido,
            mensaje: `✅ *${servicioElegido.nombre}* seleccionado.\n\n📅 *¿Qué día prefieres?*\n\nEscribe la fecha en formato:\n*DD/MM/YYYY* (ejemplo: *15/07/2025*)\n\nO escribe *hoy*, *mañana*, o el día de la semana\n\n❌ Escribe *cancelar* para salir.`,
            abierto
          }
        };
      }

      let msgInvalido = `❌ Opción no válida. Escribe un número del *1* al *${servicios.length}*:\n\n`;
      servicios.forEach((s, i) => { msgInvalido += `*${i + 1}.* ${s.nombre}\n`; });
      msgInvalido += `\n❌ O escribe *cancelar* para salir.`;
      return {
        json: {
          ...config,
          numeroOrigen: webhook.numeroOrigen,
          empresaId: webhook.empresaId,
          nombreSesion,
          pushName: webhook.pushName,
          jidOriginal,
          numeroDescifrado,
          mensaje_usuario: mensajeLimpio,
          mensaje: msgInvalido,
          tipo: 'respuesta_directa',
          abierto
        }
      };
    }

    // ── SELECCIONANDO FECHA ────────────────────────────────────────────
    if (estadoActual === 'seleccionando_fecha') {
      if (mensajeLimpio === 'cancelar') {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '✅ Operación cancelada.\n\n📋 Escribe *servicios* para ver nuestro catálogo.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }

      // Interpretar fecha natural o formato DD/MM/YYYY
      const ZONA = 'America/Hermosillo';
      const ahoraLocal = new Date(new Date().toLocaleString('en-US', { timeZone: ZONA }));
      let fechaReserva = null;
      let fechaTexto = '';

      const matchFecha = mensajeLimpio.match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/);
      if (matchFecha) {
        const d = parseInt(matchFecha[1]);
        const m = parseInt(matchFecha[2]) - 1;
        const y = matchFecha[3].length === 2 ? 2000 + parseInt(matchFecha[3]) : parseInt(matchFecha[3]);
        fechaReserva = new Date(y, m, d);
        fechaTexto = `${String(d).padStart(2,'0')}/${String(m+1).padStart(2,'0')}/${y}`;
      } else if (mensajeLimpio.includes('hoy')) {
        fechaReserva = new Date(ahoraLocal);
        fechaTexto = fechaReserva.toLocaleDateString('es-MX', { day:'2-digit', month:'2-digit', year:'numeric' });
      } else if (mensajeLimpio.includes('mañana') || mensajeLimpio.includes('manana')) {
        fechaReserva = new Date(ahoraLocal);
        fechaReserva.setDate(fechaReserva.getDate() + 1);
        fechaTexto = fechaReserva.toLocaleDateString('es-MX', { day:'2-digit', month:'2-digit', year:'numeric' });
      } else {
        const diasSemana = { 'lunes': 1, 'martes': 2, 'miercoles': 3, 'miércoles': 3, 'jueves': 4, 'viernes': 5, 'sabado': 6, 'sábado': 6, 'domingo': 0 };
        for (const [nombre, numDia] of Object.entries(diasSemana)) {
          if (mensajeLimpio.includes(nombre)) {
            const hoy = ahoraLocal.getDay();
            let diff = numDia - hoy;
            if (diff <= 0) diff += 7;
            fechaReserva = new Date(ahoraLocal);
            fechaReserva.setDate(fechaReserva.getDate() + diff);
            fechaTexto = fechaReserva.toLocaleDateString('es-MX', { day:'2-digit', month:'2-digit', year:'numeric' });
            break;
          }
        }
      }

      if (!fechaReserva) {
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '⚠️ *Fecha no reconocida*\n\nPor favor escribe la fecha así:\n*DD/MM/YYYY* (ejemplo: *15/07/2025*)\n\nO escribe: *hoy*, *mañana* o el día de la semana (lunes, martes...)\n\n❌ O escribe *cancelar* para salir.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }

      // Guardar fecha y pedir hora
      await this.helpers.httpRequest({
        method: 'PUT',
        url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
        headers: { 'Content-Type': 'application/json' },
        body: {
          estado: 'seleccionando_hora',
          datosPedido: { ...datosSesion, fechaSeleccionada: fechaTexto, fechaISO: fechaReserva.toISOString().split('T')[0] }
        },
        json: true
      });

      const servicioNombre = datosSesion?.servicioSeleccionado?.nombre || 'el servicio';
      return {
        json: {
          ...config,
          numeroOrigen: webhook.numeroOrigen,
          empresaId: webhook.empresaId,
          nombreSesion,
          pushName: webhook.pushName,
          jidOriginal,
          numeroDescifrado,
          mensaje_usuario: mensajeLimpio,
          tipo: 'respuesta_directa',
          mensaje: `📅 *Fecha seleccionada: ${fechaTexto}*\n\n⏰ *¿A qué hora prefieres?*\n\nEscribe la hora en formato de 24hrs:\n*HH:MM* (ejemplo: *10:00*, *14:30*)\n\n❌ Escribe *cancelar* para salir.`,
          abierto
        }
      };
    }

    // ── SELECCIONANDO HORA ─────────────────────────────────────────────
    if (estadoActual === 'seleccionando_hora') {
      if (mensajeLimpio === 'cancelar') {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '✅ Operación cancelada.\n\n📋 Escribe *servicios* para ver nuestro catálogo.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }

      const matchHora = mensajeLimpio.match(/^(\d{1,2}):(\d{2})$/);
      if (!matchHora) {
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '⚠️ *Hora no reconocida*\n\nEscribe la hora así:\n*HH:MM* (ejemplo: *10:00* o *14:30*)\n\n❌ O escribe *cancelar* para salir.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }

      const horaStr = `${matchHora[1].padStart(2,'0')}:${matchHora[2]}`;
      const fechaISO = datosSesion?.fechaISO;
      const fechaHoraISO = `${fechaISO}T${horaStr}:00`;

      // Guardar hora y pedir nombre
      await this.helpers.httpRequest({
        method: 'PUT',
        url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
        headers: { 'Content-Type': 'application/json' },
        body: {
          estado: 'esperando_nombre',
          datosPedido: { ...datosSesion, horaSeleccionada: horaStr, fechaHoraISO }
        },
        json: true
      });

      return {
        json: {
          ...config,
          numeroOrigen: webhook.numeroOrigen,
          empresaId: webhook.empresaId,
          nombreSesion,
          pushName: webhook.pushName,
          jidOriginal,
          numeroDescifrado,
          mensaje_usuario: mensajeLimpio,
          tipo: 'respuesta_directa',
          mensaje: `⏰ *Hora seleccionada: ${horaStr}*\n\n📝 *¿Cuál es tu nombre completo?*\n\nEscribe tu nombre para confirmar la cita.\n\n❌ O escribe *cancelar* para salir.`,
          abierto
        }
      };
    }

    // ── ESPERANDO NOMBRE PARA CITA ─────────────────────────────────────
    if (estadoActual === 'esperando_nombre') {
      const esComando =
        mensajeLimpio === 'cancelar' ||
        /^\d+$/.test(mensajeLimpio) ||
        /\b(servicios?|cat[aá]logo|agendar|reservar|cita)\b/i.test(mensajeLimpio) ||
        /\b(mis?\s+citas?|ver\s+mis?\s+citas?)\b/i.test(mensajeLimpio) ||
        /\b(?:cancelar|cancela)\s+(?:cita|reserva)\s*#?\d+\b/i.test(mensajeLimpio) ||
        /\b(hola|buenas|buenos dias|buenas tardes|buenas noches)\b/i.test(mensajeLimpio);

      if (esComando) {
        try {
          await this.helpers.httpRequest({
            method: 'DELETE',
            url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
            json: true
          });
        } catch(e) {}
        // Cae al flujo normal
      } else {
        if (mensaje.trim().length < 3) {
          return {
            json: {
              ...config,
              numeroOrigen: webhook.numeroOrigen,
              empresaId: webhook.empresaId,
              nombreSesion,
              pushName: webhook.pushName,
              jidOriginal,
              numeroDescifrado,
              mensaje_usuario: mensajeLimpio,
              mensaje: '⚠️ *Nombre muy corto*\n\n📝 Escribe tu nombre completo (mínimo 3 caracteres).\n\n❌ O escribe *cancelar* para anular.',
              tipo: 'respuesta_directa',
              abierto
            }
          };
        }

        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            nombreCliente: mensaje.trim(),
            servicioId: datosSesion?.servicioSeleccionado?.id,
            servicioNombre: datosSesion?.servicioSeleccionado?.nombre,
            fechaReservacion: datosSesion?.fechaHoraISO,
            fechaTexto: datosSesion?.fechaSeleccionada,
            horaTexto: datosSesion?.horaSeleccionada,
            tipo: 'crear_reservacion',
            mensaje: '✅ *Confirmando tu cita...*',
            mensaje_usuario: mensajeLimpio,
            abierto
          }
        };
      }
    }

    // ── ESPERANDO PERSONAS ─────────────────────────────────────────────
    if (estadoActual === 'esperando_personas') {
      if (mensajeLimpio === 'cancelar') {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '✅ Operación cancelada.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }
      const numPersonas = parseInt(mensajeLimpio);
      if (isNaN(numPersonas) || numPersonas < 1) {
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '⚠️ Escribe el número de personas (ejemplo: *1*, *2*, *3*)\n\n❌ O escribe *cancelar* para salir.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }
      await this.helpers.httpRequest({
        method: 'PUT',
        url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
        headers: { 'Content-Type': 'application/json' },
        body: {
          estado: 'esperando_nombre',
          datosPedido: { ...datosSesion, numeroPersonas: numPersonas }
        },
        json: true
      });
      return {
        json: {
          ...config,
          numeroOrigen: webhook.numeroOrigen,
          empresaId: webhook.empresaId,
          nombreSesion,
          pushName: webhook.pushName,
          jidOriginal,
          numeroDescifrado,
          mensaje_usuario: mensajeLimpio,
          tipo: 'respuesta_directa',
          mensaje: `👥 *${numPersonas} persona(s)* registrada(s).\n\n📝 *¿Cuál es tu nombre completo?*\n\n❌ O escribe *cancelar* para salir.`,
          abierto
        }
      };
    }
  }
} catch (error) {
  console.log('ℹ️ No hay sesión activa:', error.message);
}

// ── CANCELAR sin sesión ──────────────────────────────────────────────────
if (esCancelarGeneral) {
  return {
    json: {
      ...config,
      numeroOrigen: webhook.numeroOrigen,
      empresaId: webhook.empresaId,
      nombreSesion,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      mensaje_usuario: mensajeLimpio,
      mensaje: 'ℹ️ *No tienes ninguna cita activa en proceso*\n\n📋 Escribe *servicios* para ver nuestro catálogo\n📅 Escribe *agendar* para reservar una cita\n\n💬 ¿En qué puedo ayudarte?',
      tipo: 'respuesta_directa',
      abierto
    }
  };
}

// ── FLUJO NORMAL ─────────────────────────────────────────────────────────
const mensajeLower = mensajeLimpio.toLowerCase();
let tipoMensaje = 'fallback';
let mensajeRespuesta = '';

const confirmacionesSimples = ['si', 'sí', 'ok', 'vale', 'okey', 'okay', 'de acuerdo', 'claro', 'bueno', 'listo', 'entendido', 'perfecto', 'dale', 'ya', 'bien'];
if (confirmacionesSimples.includes(mensajeLower)) {
  return {
    json: {
      ...config,
      mensaje_usuario: mensajeLimpio,
      numeroOrigen: webhook.numeroOrigen,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      empresaId: webhook.empresaId,
      nombreSesion,
      conectado: config.conectado,
      abierto,
      hora_actual: hour,
      dia_actual: day,
      tipo: 'fallback',
      mensaje: abierto ? config.mensaje_horario : config.mensaje_fuera_horario
    }
  };
}

const saludos = ['hola', 'buenas', 'buenos dias', 'buenas tardes', 'buenas noches', 'buen dia', 'hey', 'ola', 'que tal', 'buenos días'];
if (saludos.some(s => mensajeLower.includes(s))) {
  tipoMensaje = 'saludo_inicial';
} else if (
  mensajeLower.includes('horario') || mensajeLower.includes('hora') ||
  mensajeLower.includes('cuando abren') || mensajeLower.includes('cuando cierran') ||
  mensajeLower.includes('que hora') || mensajeLower.includes('a que hora')
) {
  tipoMensaje = 'mostrar_horario';
} else if (
  mensajeLower.includes('servicio') || mensajeLower.includes('catalogo') ||
  mensajeLower.includes('catálogo') || mensajeLower.includes('que ofrecen') ||
  mensajeLower.includes('que hacen') || mensajeLower.includes('ver servicios')
) {
  tipoMensaje = 'ver_servicios';
} else if (
  mensajeLower.includes('agendar') || mensajeLower.includes('reservar') ||
  mensajeLower.includes('cita') || mensajeLower.includes('turno') ||
